module top_module(
  input [n-1:0] in,
  output out
);parameter n = 8; // number of input signals

reg [n-1:0] input_buffer;
reg parity;

integer i;
always @(*) begin
  input_buffer = in;
  parity = 1'b0;
  for (i = 0; i < n; i = i + 1) begin
    parity = parity ^ input_buffer[i];
  end
end

assign out = ~parity;

endmodule
